const raw = $json.output || $json.text || $json;

let parsed;

try {
  if (typeof raw === 'string') {
    parsed = JSON.parse(raw);
  } else {
    parsed = raw;
  }
} catch (error) {
  parsed = {
    intent: 'unclear',
    service: 'unknown',
    confidence: 0,
    language: 'unknown',
    extracted_fields: {},
    needs_human: false
  };
}

return [
  {
    json: {
      ...$json,
      intent: parsed.intent || 'unclear',
      service: parsed.service || 'unknown',
      confidence: parsed.confidence || 0,
      language: parsed.language || 'unknown',
      extracted_fields: parsed.extracted_fields || {},
      needs_human: parsed.needs_human || false
    }
  }
];

const item = $input.first();
const input = item.json || {};
const binary = item.binary || {};

const binaryKeys = Object.keys(binary || {});
const firstBinaryKey = binaryKeys[0] || '';

let attachmentBase64 = '';
let attachmentBinaryKey = '';
let fileName = '';
let fileExtension = '';
let mimeType = '';
let fileSize = '';

if (firstBinaryKey && binary[firstBinaryKey]) {
  const file = binary[firstBinaryKey];

  const buffer = await this.helpers.getBinaryDataBuffer(0, firstBinaryKey);
  attachmentBase64 = buffer.toString('base64');

  attachmentBinaryKey = firstBinaryKey;
  fileName = file.fileName || file.filename || '';
  mimeType = file.mimeType || file.mimetype || '';
  fileSize = file.fileSize || file.file_size || '';

  if (fileName && fileName.includes('.')) {
    fileExtension = fileName.split('.').pop();
  }
}

const hasAttachment = !!attachmentBase64;

return [
  {
    json: {
      ...input,

      attachment_base64: attachmentBase64,
      attachment_base64_available: hasAttachment,

      has_attachment: hasAttachment,
      attachment_count: hasAttachment ? 1 : 0,

      attachment_file_name: fileName,
      attachment_file_extension: fileExtension,
      attachment_mime_type: mimeType,
      attachment_file_size: fileSize,

      attachment_binary_key: attachmentBinaryKey,
      attachment_info: hasAttachment
        ? `${fileName} | ${mimeType} | ${fileSize}`
        : ''
    },
    binary
  }
];
